/**
 * @name TarArchiveEntry name flowing to file construction in Copy.java
 * @description Archive entry name used to construct file paths without path validation (zip/tar slip)
 * @kind path-problem
 * @problem.severity error
 * @id java/tar-slip-copy
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module TarSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Any getName() call on an archive-related type
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      source.asExpr() = mc
    )
    or
    // getNextTarEntry, getNextEntry, etc.
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getNextTarEntry") or
        mc.getMethod().hasName("getNextEntry") or
        mc.getMethod().hasName("getNextZipEntry")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileOutputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileInputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get()
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Block if there's a canonical path check
    exists(MethodCall mc |
      (mc.getMethod().hasName("getCanonicalPath") or
       mc.getMethod().hasName("toRealPath") or
       mc.getMethod().hasName("startsWith")) and
      node.asExpr() = mc
    )
  }
}

module TarSlipFlow = TaintTracking::Global<TarSlipConfig>;
import TarSlipFlow::PathGraph

from TarSlipFlow::PathNode source, TarSlipFlow::PathNode sink
where 
  TarSlipFlow::flowPath(source, sink) and
  sink.getNode().asExpr().getFile().getRelativePath().matches("%Copy.java%")
select sink.getNode(), source, sink, "Archive entry name from $@ flows to file construction - potential path traversal.", source.getNode(), "archive entry name"

/**
 * @name Archive entry name used in file construction without canonical path check
 * @description ArchiveEntry.getName() flows to File constructor or FileOutputStream without canonicalization/containment check
 * @kind path-problem
 * @problem.severity error
 * @id java/tar-slip-no-canonical
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module TarSlipNoCanonConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.compress.archivers", "ArchiveEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor with entry name argument
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileOutputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Canonicalization calls block flow
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getCanonicalPath") or
        mc.getMethod().hasName("getCanonicalFile") or
        mc.getMethod().hasName("toRealPath") or
        mc.getMethod().hasName("normalize")
      ) and
      node.asExpr() = mc
    )
  }
}

module TarSlipNoCanonFlow = TaintTracking::Global<TarSlipNoCanonConfig>;
import TarSlipNoCanonFlow::PathGraph

from TarSlipNoCanonFlow::PathNode source, TarSlipNoCanonFlow::PathNode sink
where TarSlipNoCanonFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Tar Slip: ArchiveEntry.getName() from $@ flows to file construction without path canonicalization.", source.getNode(), "archive entry getName()"
